import{_ as a,o as b,c as t,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"未来道具","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/未来道具 .md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/未来道具 .md"}'),p={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/未来道具 .md"};function d(o,e,_,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"未来道具",tabindex:"-1"},[s("未来道具 "),r("a",{class:"header-anchor",href:"#未来道具","aria-label":'Permalink to "未来道具"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="未来道具-1" tabindex="-1">未来道具 <a class="header-anchor" href="#未来道具-1" aria-label="Permalink to &quot;未来道具&quot;">​</a></h1><p>未来道具系列</p><p>未来道具1号机--比特粒子炮<br> 10分<br> 奇物<br> 科技本质<br> 未来装置研究所极具荣耀的第一件发明，在玩具光线枪中强行塞入电视机遥控器，朝着电视机扣下扳机的话，就能如同射击一般切换频道。<br> 持有比特粒子炮，你可以用上面的按钮操控任何无支线的电视机，当然，因为比特粒子炮上只有“下一个频道”的按钮，因此你只能操控电视机跳到下一个频道，其他诸如音量调整等均无法使用。<br> 你可以花费10积分改造比特粒子炮，在上面多加一个按钮。<br> 比特粒子炮现在可以按关机键控制电视机关机。</p><p>未来道具2号机--竹蜻蜓摄影机<br> 10分<br> 奇物<br> 科技本质<br> 竹蜻蜓式CCD摄影机。竹蜻蜓的支棍内安有CCD摄影机，可以无动力状态下进行空中摄影。但拍摄到的影像因为飞速旋转，看久了的话会感到目眩恶心。<br> 非战斗状态下，一个动作放飞竹蜻蜓，由于材料限制，竹蜻蜓放飞后，与你之间距离不会超过5m。<br> 竹蜻蜓下落过程中，其内部摄像头会随着竹蜻蜓一起旋转。<br> 当有人试图理解其拍摄的视频时，需要过一个dc6的意志检定，失败获得差值的目眩与恶心异常点数。<br> 你可以花费10积分强化竹蜻蜓摄像机，在其内部增加陀螺仪。<br> 现在竹蜻蜓拍摄时，摄像头不会跟着一起旋转，观看拍摄视频，无需意志鉴定。</p><p>未来道具3号机--难道是要硬来吗！？<br> 10分<br> 奇物<br> 科技本质<br> 能根据拇指的出汗情况来进行判定的测谎仪。也许叫做汗水检测器更加正确，但是只要认为是个很厉害的发明就行了。<br> 当有人握着握把时，如果因为紧张手中出汗，该装置就会发出报警声。<br> 当然，如果你手上本来就有手汗，握上去的一瞬间就会报警。</p><p>未来道具4号机--又把无聊的东西连在一起了by五右卫门<br> 10分<br> 奇物<br> 科技本质<br> 让吹风机与吸尘器合体后诞生的，梦幻般的未来装置。利用吸尘器的排气来驱动吹风机同时运行。<br> 需要注意的是，在正常普通住宅中，如果在使用未来机器5时，不把其他电器开关关闭，则在使用瞬间，需要投掷一个d10-x（x为除了未来装置外其他运行设备数量）如果结果小于等于7，则总电路跳闸。<br> 电力配备齐全的设施不会因为电器功率过载而跳闸，具体情况，由st决定。</p><p>未来道具5号机--光束剑<br> 250<br> 奇物<br> 科技本质<br> 可以通过化学反应产生红光的塑料荧光棒，因为装上了柄所以可以像剑那样拿着。这件发明将“让血浆发光”这种谁都能想不到的划时代的点子成为了现实。未来装置研究所不只是硬件方面，化学方面的发明也是可能的!<br> 极为炫酷的发光激光剑，然而它并非实战武器，只需一个简单动作即可将其折断，并释放出内部流淌的血浆。<br> 你可以巧妙运用这血浆来迷惑对手，敌人需通过侦查鉴定来对抗你的伪装鉴定。若侦查失败，敌人将误以为你已经身亡，这相当于一种无支线的假死效果。任何具备本质特性的侦查手段都能识破这血液的虚假本质，从而揭露你的计谋。<br> 你可以花费750分进行强化，强化后，内部的血浆将更加逼真，且不会凝固，这将使假死效果提升至D级。</p><p>未来道具6号机--攻壳机动迷彩球<br> 10分<br> 奇物<br> 科技本质<br> 未来装置6号机。将约12台二手的6寸布朗管电视机，全部都以画面朝外的形式组成的球体。在电视机的夹缝之间，还插入了复数个超小型的C一MOS摄像头。每个摄像头正好与球体另一侧的一台电视机相连，与电视机成对的摄像头都与电视机保持着90度直角，并且镜头朝外。这样一来就形成了一个好像使用了光学迷彩技术的多边形球体。这项发明可谓是至目前为止的未来装置中的最高杰作。不过由于这东西的个头实在是够大所以放在屋里相当碍事。<br> 一个只能摆在主神空间，无法带入副本世界的时尚小道具。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(p,[["render",d]]);export{f as __pageData,m as default};
